    10→
    11→const BASE_SLOT_HEIGHT = 50; // px per 15-minute slot
    12→const BASE_SLOT_MINUTES = 15;
    13→
    14→const getInitials = (name: string): string => {
    15→  const parts = name.trim().split(" ").filter(Boolean);
    16→  if (parts.length >= 2) {
    17→    return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
    18→  }
    19→  return name.substring(0, 2).toUpperCase();
    20→};
    21→
    22→const generateTimeSlots = (
    23→  startHour: number,
    24→  endHour: number,
    25→  slotMinutes: number
    26→): TimeSlot[] => {
    27→  const slots: TimeSlot[] = [];
    28→  let currentHour = startHour;
    29→  let currentMinute = 0;
    30→
    31→  while (
    32→    currentHour < endHour ||
    33→    (currentHour === endHour && currentMinute === 0)
    34→  ) {
    35→    const label = `${currentHour.toString().padStart(2, "0")}:${currentMinute
    36→      .toString()
    37→      .padStart(2, "0")}`;
    38→    const time = `${currentHour}:${currentMinute.toString().padStart(2, "0")}`;
    39→
    40→    slots.push({
    41→      hour: currentHour,
    42→      minute: currentMinute,
    43→      label,
    44→      time,
    45→    });
    46→
    47→    currentMinute += slotMinutes;
    48→    if (currentMinute >= 60) {
    49→      currentMinute = 0;
    50→      currentHour += 1;
    51→    }
    52→  }
    53→
    54→  return slots;
    55→};
    56→
    57→const calculateCurrentTimePosition = (
    58→  currentDate: Date,
    59→  timeSlots: TimeSlot[],
    60→  slotHeight: number,
    61→  timezone?: string
    62→): number | undefined => {
    63→  if (timeSlots.length === 0) return undefined;
    64→
    65→  const currentHour = timezone
    66→    ? parseInt(formatInTimeZone(currentDate, timezone, "HH"), 10)
    67→    : currentDate.getHours();
    68→  const currentMinute = timezone
    69→    ? parseInt(formatInTimeZone(currentDate, timezone, "mm"), 10)
    70→    : currentDate.getMinutes();
    71→
    72→  const firstSlot = timeSlots[0];
    73→  const currentTotalMinutes = currentHour * 60 + currentMinute;
    74→  const firstSlotMinutes = firstSlot.hour * 60 + firstSlot.minute;
    75→
    76→  if (currentTotalMinutes < firstSlotMinutes) return 0;
    77→
    78→  const minutesFromFirst = currentTotalMinutes - firstSlotMinutes;
    79→
    80→  const slotMinutes =
    81→    timeSlots.length > 1
    82→      ? timeSlots[1].hour * 60 + timeSlots[1].minute - firstSlotMinutes
    83→      : 15;
    84→
    85→  return (minutesFromFirst / slotMinutes) * slotHeight;
    86→};
