    88→export const EasyCalendar: React.FC<EasyCalendarProps> = ({
    89→  date,
    90→  columns,
    91→  events,
    92→  startHour = 8,
    93→  endHour = 20,
    94→  slotMinutes = 15,
    95→  primaryColor,
    96→  salonTimezone = "America/Sao_Paulo",
    97→  onEventClick,
    98→  onSlotClick,
    99→  onAbsenceClick,
   100→  onAbsenceBlockClick,
   101→  loading = false,
   102→  isSalonClosed = false,
   103→  focusAppointment = null,
   104→  onFocusConsumed,
   105→  containerClassName,
   106→}) => {
   107→  const bodyScrollRef = useRef<HTMLDivElement>(null);
   108→  const headerScrollRef = useRef<HTMLDivElement>(null);
   109→  const footerScrollRef = useRef<HTMLDivElement>(null);
   110→  const [currentTime, setCurrentTime] = useState(new Date());
   111→
   112→  const timeSlots = useMemo(
   113→    () => generateTimeSlots(startHour, endHour, slotMinutes),
   114→    [startHour, endHour, slotMinutes]
   115→  );
   116→
   117→  const slotHeight = useMemo(
   118→    () => (slotMinutes / BASE_SLOT_MINUTES) * BASE_SLOT_HEIGHT,
   119→    [slotMinutes]
   120→  );
   121→
   122→  const calendarDate = useMemo(
   123→    () => new Date(date + "T00:00:00.000Z"),
   124→    [date]
   125→  );
   126→
   127→  const isTodayDate = useMemo(() => {
   128→    const nowInSalonTz = toZonedTime(new Date(), salonTimezone);
   129→    const todayInSalonTz = formatInTimeZone(
   130→      nowInSalonTz,
   131→      salonTimezone,
   132→      "yyyy-MM-dd"
   133→    );
   134→    return date === todayInSalonTz;
   135→  }, [date, salonTimezone]);
   136→
   137→  const isPastDay = useMemo(
   138→    () => isBefore(startOfDay(calendarDate), startOfDay(new Date())),
   139→    [calendarDate]
   140→  );
   141→
   142→  const currentTimePosition = useMemo(() => {
   143→    if (!isTodayDate) return undefined;
   144→    return calculateCurrentTimePosition(
   145→      currentTime,
   146→      timeSlots,
   147→      slotHeight,
   148→      salonTimezone
   149→    );
   150→  }, [isTodayDate, currentTime, timeSlots, slotHeight, salonTimezone]);
   151→
   152→  useEffect(() => {
   153→    if (!isTodayDate) return;
   154→    const interval = setInterval(() => setCurrentTime(new Date()), 60000);
   155→    return () => clearInterval(interval);
   156→  }, [isTodayDate]);
   157→
   158→  // Sync header and footer scrollbars when body scrolls horizontally
   159→  const handleBodyScroll = useCallback(() => {
   160→    const left = bodyScrollRef.current?.scrollLeft ?? 0;
   161→    if (headerScrollRef.current) headerScrollRef.current.scrollLeft = left;
   162→    if (footerScrollRef.current) footerScrollRef.current.scrollLeft = left;
   163→  }, []);
   164→
   165→  // Sync body and header when user drags the footer scrollbar
   166→  const handleFooterScroll = useCallback(() => {
   167→    const left = footerScrollRef.current?.scrollLeft ?? 0;
   168→    if (bodyScrollRef.current) bodyScrollRef.current.scrollLeft = left;
   169→    if (headerScrollRef.current) headerScrollRef.current.scrollLeft = left;
   170→  }, []);
   171→
   172→  // Focus and Scroll Effect
   173→  useEffect(() => {
   174→    if (!focusAppointment || loading) return;
   175→
   176→    const timer = setTimeout(() => {
   177→      const profColumn = bodyScrollRef.current?.querySelector(
   178→        `[data-professional-id="${focusAppointment.professionalId}"]`
   179→      );
   180→      if (profColumn) {
   181→        profColumn.scrollIntoView({ behavior: "smooth", block: "nearest", inline: "start" });
   182→      }
   183→
   184→      const timeLabel = bodyScrollRef.current?.querySelector(
   185→        `[data-time-slot="${focusAppointment.time}"]`
   186→      );
   187→      if (timeLabel) {
   188→        timeLabel.scrollIntoView({ behavior: "smooth", block: "center" });
   189→      }
   190→
   191→      setTimeout(() => onFocusConsumed?.(), 4000);
   192→    }, 150);
   193→
   194→    return () => clearTimeout(timer);
   195→  }, [focusAppointment, loading, onFocusConsumed]);
   196→
   197→  const outerClass =
   198→    containerClassName ?? "border border-border bg-card rounded-lg h-[calc(100vh-280px)] w-full";
   199→
   200→  if (loading) {
   201→    return (
   202→      <div className={outerClass}>
   203→        <div className="flex items-center justify-center h-full">
   204→          <LoadingSpinner size="md" />
   205→        </div>
   206→      </div>
   207→    );
   208→  }
   209→
   210→  if (isSalonClosed) {
   211→    return (
   212→      <div className={outerClass}>
   213→        <div className="flex flex-col items-center justify-center h-full px-4 text-center">
   214→          <h3 className="text-section-title font-semibold text-foreground mb-2">
   215→            Salão fechado neste dia
   216→          </h3>
   217→          <p className="text-body text-muted-foreground max-w-md">
   218→            O salão não está aberto na data selecionada. Verifique os horários
   219→            de funcionamento ou selecione outro dia.
   220→          </p>
   221→        </div>
   222→      </div>
   223→    );
   224→  }
   225→
   226→  if (columns.length === 0) {
   227→    return (
   228→      <div className={outerClass}>
   229→        <div className="flex flex-col items-center justify-center h-full px-4 text-center">
   230→          <h3 className="text-section-title font-semibold text-foreground mb-2">
   231→            Nenhum profissional cadastrado
   232→          </h3>
   233→          <p className="text-body text-muted-foreground max-w-md">
   234→            Para utilizar a agenda, é necessário cadastrar pelo menos um
   235→            profissional no salão.
   236→          </p>
   237→          <p className="text-body text-muted-foreground mt-2">
   238→            Acesse <span className="font-semibold">Gestão de Acesso</span> para
   239→            cadastrar profissionais.
   240→          </p>
   241→        </div>
   242→      </div>
   243→    );
   244→  }
   245→
   246→  return (
   247→    <div className={cn(outerClass, "flex flex-col overflow-hidden")}>
   248→
   249→      {/* ── Row 1: Fixed professional header (no vertical scroll) ── */}
   250→      <div className="flex-shrink-0 border-b border-border flex">
   251→        {/* Time gutter — same width as TimeGrid */}
   252→        <div className="w-20 flex-shrink-0 bg-secondary border-r border-border" />
   253→        {/* Header cells — scrolls horizontally in sync with body via JS */}
   254→        <div ref={headerScrollRef} className="flex-1 min-w-0 overflow-hidden">
   255→          <div className="flex">
   256→            {columns.map((column: ProfessionalColumnType, index: number) => (
   257→              <div
   258→                key={column.id}
   259→                className={cn(
   260→                  "flex-1 min-w-0 px-2 py-2 md:px-4 md:py-3 text-center flex flex-col justify-center border-r border-border last:border-r-0",
   261→                  columns.length > 1 && "min-w-[160px] md:min-w-[300px]",
   262→                  index % 2 === 0 ? "bg-secondary" : "bg-card"
   263→                )}
   264→              >
   265→                <div className="flex items-center justify-center gap-1.5">
   266→                  <span className="text-primary font-semibold text-body">
   267→                    {getInitials(getUserDisplayName(column))}
   268→                  </span>
   269→                </div>
   270→                <div className="text-button text-muted-foreground mt-1 font-normal break-words leading-tight">
   271→                  {getUserDisplayName(column)}
   272→                </div>
   273→              </div>
   274→            ))}
   275→          </div>
   276→        </div>
   277→      </div>
   278→
   279→      {/* ── Row 2: Body — scrolls BOTH axes; TimeGrid is sticky left ── */}
   280→      {/*
   281→          Key insight: the body scrolls both X and Y in a single container.
   282→          overflow-x:scroll + overflow-y:auto on the SAME element is valid CSS.
   283→          TimeGrid uses sticky left-0 so it stays visible during horizontal scroll.
   284→          Header/footer are synced via JS (scrollLeft assignment on scroll event).
   285→          The scrollbar-none class hides the native horizontal scrollbar here;
   286→          the footer row provides the visible fixed-position scrollbar.
   287→      */}
   288→      <div
   289→        ref={bodyScrollRef}
   290→        className="flex-1 min-h-0 overflow-x-scroll overflow-y-auto scrollbar-none"
   291→        onScroll={handleBodyScroll}
   292→      >
   293→        <div className="flex min-h-full">
   294→          <TimeGrid
   295→            timeSlots={timeSlots}
   296→            slotHeight={slotHeight}
   297→            currentTimePosition={currentTimePosition}
   298→          />
   299→          <div className="flex flex-1">
   300→            {columns.map((column: ProfessionalColumnType, index: number) => {
   301→              const columnEvents = events.filter(
   302→                (event) => event.professionalId === column.id
   303→              );
   304→              return (
   305→                <ProfessionalColumn
   306→                  key={column.id}
   307→                  professional={column}
   308→                  columnIndex={index}
   309→                  totalColumns={columns.length}
   310→                  events={columnEvents}
   311→                  timeSlots={timeSlots}
   312→                  slotHeight={slotHeight}
   313→                  primaryColor={primaryColor}
   314→                  onEventClick={onEventClick}
   315→                  onSlotClick={onSlotClick}
   316→                  onAbsenceClick={onAbsenceClick}
   317→                  onAbsenceBlockClick={onAbsenceBlockClick}
   318→                  isPastDay={isPastDay}
   319→                  selectedDate={calendarDate}
   320→                  highlightAppointmentId={focusAppointment?.id ?? null}
   321→                />
   322→              );
   323→            })}
   324→          </div>
   325→        </div>
   326→      </div>
   327→
   328→      {/* ── Row 3: Fixed horizontal scrollbar footer ── */}
   329→      {/*
   330→          Mirror divs match the exact scrollable width of the body.
   331→          The visible scrollbar here stays fixed at the bottom of the calendar
   332→          regardless of how far the user has scrolled vertically.
   333→          Dragging this scrollbar syncs bodyScrollRef and headerScrollRef via JS.
   334→      */}
   335→      <div className="flex-shrink-0 flex border-t border-border">
   336→        <div className="w-20 flex-shrink-0" />
   337→        <div
   338→          ref={footerScrollRef}
   339→          className="flex-1 overflow-x-scroll overflow-y-hidden"
   340→          onScroll={handleFooterScroll}
   341→        >
   342→          <div className="flex">
   343→            {columns.map((column: ProfessionalColumnType) => (
   344→              <div
   345→                key={column.id}
   346→                className={cn(
   347→                  "flex-1 min-w-0 h-0",
   348→                  columns.length > 1 && "min-w-[160px] md:min-w-[300px]"
   349→                )}
   350→              />
   351→            ))}
   352→          </div>
   353→        </div>
   354→      </div>
   355→
   356→    </div>
   357→  );
   358→};
