    99→//   const top = (startMinutesFromFirst / slotMinutes) * slotHeight;
   100→//   const height = (durationMinutes / slotMinutes) * slotHeight;
   101→
   102→//   return { top, height };
   103→// };
   104→
   105→const calculateEventPosition = (
   106→  event: CalendarEvent,
   107→  timeSlots: TimeSlot[],
   108→  slotHeight: number,
   109→  salonTimezone: string
   110→): EventPosition => {
   111→  // Converter UTC para timezone do salão
   112→  const startTime = extractTimeComponents(event.start, salonTimezone);
   113→  const endTime = extractTimeComponents(event.end, salonTimezone);
   114→
   115→  const startHour = startTime.hours;
   116→  const startMinute = startTime.minutes;
   117→  const endHour = endTime.hours;
   118→  const endMinute = endTime.minutes;
   119→
   120→  const firstSlot = timeSlots[0];
   121→  const lastSlot = timeSlots[timeSlots.length - 1];
   122→
   123→  const firstSlotMinutes = firstSlot.hour * 60 + firstSlot.minute;
   124→  const lastSlotMinutes = lastSlot.hour * 60 + lastSlot.minute;
   125→
   126→  const eventStartMinutes = startHour * 60 + startMinute;
   127→  const eventEndMinutes = endHour * 60 + endMinute;
   128→
   129→  // Calculate slot duration dynamically
   130→  const slotMinutes =
   131→    timeSlots.length > 1
   132→      ? timeSlots[1].hour * 60 + timeSlots[1].minute - firstSlotMinutes
   133→      : 15;
   134→
   135→  // Clamp event start to visible area
   136→  const clampedStartMinutes = Math.max(eventStartMinutes, firstSlotMinutes);
   137→  const clampedEndMinutes = Math.min(eventEndMinutes, lastSlotMinutes + slotMinutes);
   138→
   139→  const startMinutesFromFirst = clampedStartMinutes - firstSlotMinutes;
   140→  const durationMinutes = clampedEndMinutes - clampedStartMinutes;
   141→
   142→  const top = (startMinutesFromFirst / slotMinutes) * slotHeight;
   143→  const height = Math.max((durationMinutes / slotMinutes) * slotHeight, 25); // Minimum 25px height (half slot)
   144→
   145→  return { top, height };
   146→};
   147→
   148→/**
   149→ * Verifica se dois eventos se sobrepõem temporalmente
   150→ */
   151→const eventsOverlap = (event1: CalendarEvent, event2: CalendarEvent): boolean => {
   152→  const start1 = new Date(event1.start).getTime();
   153→  const end1 = new Date(event1.end).getTime();
   154→  const start2 = new Date(event2.start).getTime();
   155→  const end2 = new Date(event2.end).getTime();
   156→
   157→  return start1 < end2 && start2 < end1;
   158→};
   159→
   160→/**
   161→ * Detecta grupos de eventos que se sobrepõem
   162→ * Retorna array de grupos, onde cada grupo contém eventos sobrepostos
   163→ */
   164→const detectCollisionGroups = (events: CalendarEvent[]): CalendarEvent[][] => {
   165→  if (events.length === 0) return [];
   166→
   167→  // Ordena eventos por horário de início, depois por ID (ordem de criação)
   168→  const sortedEvents = [...events].sort((a, b) => {
   169→    const timeCompare = new Date(a.start).getTime() - new Date(b.start).getTime();
   170→    if (timeCompare !== 0) return timeCompare;
   171→    return a.id.localeCompare(b.id);
   172→  });
   173→
   174→  const groups: CalendarEvent[][] = [];
   175→  const processed = new Set<string>();
   176→
   177→  sortedEvents.forEach((event) => {
   178→    if (processed.has(event.id)) return;
   179→
   180→    // Inicia novo grupo com este evento
   181→    const group = [event];
   182→    processed.add(event.id);
   183→
   184→    // Encontra todos os eventos que se sobrepõem com algum evento do grupo
   185→    let foundOverlap = true;
   186→    while (foundOverlap) {
   187→      foundOverlap = false;
   188→      sortedEvents.forEach((candidate) => {
   189→        if (processed.has(candidate.id)) return;
   190→
   191→        // Verifica se candidate se sobrepõe com algum evento do grupo
   192→        const overlaps = group.some((groupEvent) =>
   193→          eventsOverlap(groupEvent, candidate)
   194→        );
   195→
   196→        if (overlaps) {
   197→          group.push(candidate);
   198→          processed.add(candidate.id);
   199→          foundOverlap = true;
   200→        }
   201→      });
   202→    }
   203→
   204→    groups.push(group);
   205→  });
   206→
   207→  return groups;
   208→};
   209→
   210→/**
   211→ * Calcula o layout (sub-coluna) para cada evento considerando colisões
   212→ */
   213→const calculateEventLayouts = (
   214→  events: CalendarEvent[],
   215→  timeSlots: TimeSlot[],
   216→  slotHeight: number,
   217→  salonTimezone: string
   218→): EventLayout[] => {
   219→  if (events.length === 0) return [];
   220→
   221→  const collisionGroups = detectCollisionGroups(events);
   222→  const layouts: EventLayout[] = [];
   223→
   224→  collisionGroups.forEach((group) => {
   225→    if (group.length === 1) {
   226→      // Sem colisão - ocupa largura total
   227→      const event = group[0];
   228→      layouts.push({
   229→        event,
   230→        position: calculateEventPosition(event, timeSlots, slotHeight, salonTimezone),
   231→        column: 0,
   232→        totalColumns: 1,
   233→      });
   234→    } else {
   235→      // Múltiplos eventos sobrepostos - calcula sub-colunas
   236→      // Ordena grupo por início e ID
   237→      const sortedGroup = [...group].sort((a, b) => {
   238→        const timeCompare = new Date(a.start).getTime() - new Date(b.start).getTime();
   239→        if (timeCompare !== 0) return timeCompare;
   240→        return a.id.localeCompare(b.id);
   241→      });
   242→
   243→      // Atribui cada evento a uma coluna
   244→      const columnAssignments = new Map<string, number>();
   245→      const maxColumnsNeeded = sortedGroup.length;
   246→
   247→      sortedGroup.forEach((event, index) => {
   248→        // Encontra a primeira coluna disponível
   249→        let column = 0;
   250→        const occupiedColumns = new Set<number>();
   251→
   252→        // Verifica quais colunas estão ocupadas por eventos que se sobrepõem
   253→        sortedGroup.forEach((other, otherIndex) => {
   254→          if (otherIndex >= index) return; // Só verifica eventos já processados
   255→
   256→          if (eventsOverlap(event, other)) {
   257→            const otherColumn = columnAssignments.get(other.id);
   258→            if (otherColumn !== undefined) {
   259→              occupiedColumns.add(otherColumn);
   260→            }
   261→          }
   262→        });
   263→
   264→        // Encontra primeira coluna livre
   265→        while (occupiedColumns.has(column)) {
   266→          column++;
   267→        }
   268→
   269→        columnAssignments.set(event.id, column);
   270→      });
   271→
   272→      // Calcula o número máximo de colunas necessárias
   273→      const maxColumn = Math.max(...Array.from(columnAssignments.values()));
   274→      const totalColumns = maxColumn + 1;
   275→
   276→      // Cria layouts para todos os eventos do grupo
   277→      sortedGroup.forEach((event) => {
   278→        layouts.push({
   279→          event,
   280→          position: calculateEventPosition(event, timeSlots, slotHeight, salonTimezone),
   281→          column: columnAssignments.get(event.id) || 0,
   282→          totalColumns,
   283→        });
   284→      });
   285→    }
   286→  });
   287→
   288→  return layouts;
   289→};
