   291→type BlockReason =
   292→  | "salon-closed"
   293→  | "past"
   294→  | "not-working"
   295→  | "outside-professional-hours"
   296→  | "break"
   297→  | "ausencia"
   298→  | "indisponibilidade";
   299→
   300→interface BlockStatus {
   301→  blocked: boolean;
   302→  reason?: BlockReason;
   303→}
   304→
   305→const DAY_MAP: Record<number, keyof ProfessionalSchedule> = {
   306→  0: "sunday",
   307→  1: "monday",
   308→  2: "tuesday",
   309→  3: "wednesday",
   310→  4: "thursday",
   311→  5: "friday",
   312→  6: "saturday",
   313→} as const;
   314→
   315→const parseTimeToMinutes = (time: string): number => {
   316→  const parts = time.split(":");
   317→  const hours = parseInt(parts[0], 10);
   318→  const minutes = parseInt(parts[1], 10);
   319→  return hours * 60 + minutes;
   320→};
   321→
   322→/**
   323→ * Default timezone for salons (Brazil/São Paulo)
   324→ * Used as fallback when salon timezone is not specified
   325→ */
   326→const DEFAULT_SALON_TIMEZONE = "America/Sao_Paulo";
   327→
   328→/**
   329→ * Gets current time in minutes in the salon's timezone
   330→ * @param salonTimezone - IANA timezone string (e.g., "America/Sao_Paulo", "Europe/Lisbon")
   331→ * @returns Current time in minutes since midnight in salon's timezone
   332→ */
   333→const getCurrentSalonTimeInMinutes = (salonTimezone?: string): number => {
   334→  const now = new Date();
   335→  const timezone = salonTimezone || DEFAULT_SALON_TIMEZONE;
   336→
   337→  // Format current time in salon's timezone as HH:mm
   338→  const timeString = formatInTimeZone(now, timezone, "HH:mm");
   339→  return parseTimeToMinutes(timeString);
   340→};
   341→
   342→const getUTCDateString = (date: Date): string => {
   343→  return date.toISOString().split("T")[0];
   344→};
   345→
   346→const getTodayUTCDateString = (): string => {
   347→  return new Date().toISOString().split("T")[0];
   348→};
   349→
   350→const isDateBeforeToday = (date: Date): boolean => {
   351→  const todayUTC = getTodayUTCDateString();
   352→  const dateUTC = getUTCDateString(date);
   353→  return dateUTC < todayUTC;
   354→};
   355→
   356→const isToday = (date: Date): boolean => {
   357→  const todayUTC = getTodayUTCDateString();
   358→  const dateUTC = getUTCDateString(date);
   359→  return dateUTC === todayUTC;
   360→};
   361→
   362→const isSlotInPast = (
   363→  slot: TimeSlot,
   364→  selectedDate: Date,
   365→  slotDurationMinutes: number,
   366→  salonTimezone?: string
   367→): boolean => {
   368→  // Rule 1: Block ALL slots if date is before today (in UTC)
   369→  if (isDateBeforeToday(selectedDate)) {
   370→    return true;
   371→  }
   372→
   373→  // Rule 2: For today (in UTC), block only slots where the next slot has started
   374→  // This gives users the full slot duration to book
   375→  // Example: If now is 11:08 and slot is 11:00-11:30, the slot should still be available
   376→  // Only block when current time >= 11:30 (next slot start)
   377→  if (isToday(selectedDate)) {
   378→    const slotStartMinutes = parseTimeToMinutes(slot.time);
   379→    const slotEndMinutes = slotStartMinutes + slotDurationMinutes;
   380→    const currentSalonMinutes = getCurrentSalonTimeInMinutes(salonTimezone);
   381→
   382→    // Block only if we're already in the next slot (current time >= slot end time)
   383→    return currentSalonMinutes >= slotEndMinutes;
   384→  }
   385→
   386→  return false;
   387→};
   388→
   389→const isSlotInBreak = (
   390→  slot: TimeSlot,
   391→  professionalSchedule: ProfessionalSchedule,
   392→  selectedDate: Date,
   393→  salonTimezone?: string
   394→): boolean => {
   395→  // Get day of week in salon timezone to ensure correct schedule lookup
   396→  const timezone = salonTimezone || DEFAULT_SALON_TIMEZONE;
   397→  const dayOfWeekInTimezone = parseInt(
   398→    formatInTimeZone(selectedDate, timezone, "e"),
   399→    10
   400→  );
   401→  // formatInTimeZone returns 1-7 (Mon-Sun), convert to 0-6 (Sun-Sat)
   402→  const dayOfWeek = dayOfWeekInTimezone === 7 ? 0 : dayOfWeekInTimezone;
   403→  const dayName = DAY_MAP[dayOfWeek];
   404→  const daySchedule = professionalSchedule[dayName];
   405→
   406→  if (!daySchedule?.breaks || daySchedule.breaks.length === 0) {
   407→    return false;
   408→  }
   409→
   410→  const slotMinutes = parseTimeToMinutes(slot.time);
   411→
   412→  // Rule 3: Check if slot falls within any break period
   413→  return daySchedule.breaks.some((breakPeriod) => {
   414→    const breakStartMinutes = parseTimeToMinutes(breakPeriod.start);
   415→    const breakEndMinutes = parseTimeToMinutes(breakPeriod.end);
   416→    return slotMinutes >= breakStartMinutes && slotMinutes < breakEndMinutes;
   417→  });
   418→};
   419→
   420→const isSlotBlocked = (
   421→  slot: TimeSlot,
   422→  breaks: ProfessionalColumnType["breaks"],
   423→  _isPastDay: boolean, // Deprecated - not used, kept for compatibility
   424→  professionalSchedule?: ProfessionalSchedule,
   425→  selectedDate?: Date,
   426→  salonIsOpen?: boolean,
   427→  salonTimezone?: string,
   428→  slotDurationMinutes: number = 15
   429→): BlockStatus => {
   430→  const result: BlockStatus = { blocked: false };
   431→
   432→  // Priority 1: Salon closed
   433→  if (salonIsOpen === false) {
   434→    result.blocked = true;
   435→    result.reason = "salon-closed";
   436→    return result;
   437→  }
   438→
   439→  if (!selectedDate) {
   440→    result.blocked = false;
   441→    return result;
   442→  }
   443→
   444→  // Priority 2: Past date or past time (Rules 1 & 2)
   445→  if (isSlotInPast(slot, selectedDate, slotDurationMinutes, salonTimezone)) {
   446→    result.blocked = true;
   447→    result.reason = "past";
   448→    return result;
   449→  }
   450→
   451→  // Priority 3: Check professional schedule restrictions
   452→  if (professionalSchedule) {
   453→    // Get day of week in salon timezone to ensure correct schedule lookup
   454→    const timezone = salonTimezone || DEFAULT_SALON_TIMEZONE;
   455→    const dayOfWeekInTimezone = parseInt(
   456→      formatInTimeZone(selectedDate, timezone, "e"),
   457→      10
   458→    );
   459→    // formatInTimeZone returns 1-7 (Mon-Sun), convert to 0-6 (Sun-Sat)
   460→    const dayOfWeek = dayOfWeekInTimezone === 7 ? 0 : dayOfWeekInTimezone;
   461→    const dayName = DAY_MAP[dayOfWeek];
   462→    const daySchedule = professionalSchedule[dayName];
   463→
   464→    if (daySchedule) {
   465→      // Professional not working this day
   466→      if (daySchedule.isWorking === false) {
   467→        result.blocked = true;
   468→        result.reason = "not-working";
   469→        return result;
   470→      }
   471→
   472→      // Check if outside professional working hours
   473→      const startTime = daySchedule.start || daySchedule.startTime;
   474→      const endTime = daySchedule.end || daySchedule.endTime;
   475→
   476→      if (startTime && endTime) {
   477→        const slotMinutes = parseTimeToMinutes(slot.time);
   478→        const professionalStartMinutes = parseTimeToMinutes(startTime);
   479→        const professionalEndMinutes = parseTimeToMinutes(endTime);
   480→
   481→        if (
   482→          slotMinutes < professionalStartMinutes ||
   483→          slotMinutes >= professionalEndMinutes
   484→        ) {
   485→          result.blocked = true;
   486→          result.reason = "outside-professional-hours";
   487→          return result;
   488→        }
   489→      }
   490→
   491→      // Priority 4: Check if slot is in break period (Rule 3)
   492→      if (
   493→        isSlotInBreak(slot, professionalSchedule, selectedDate, salonTimezone)
   494→      ) {
   495→        result.blocked = true;
   496→        result.reason = "break";
   497→        return result;
   498→      }
   499→    }
   500→  }
   501→
   502→  // Priority 5: Check for registered absences and breaks
   503→  if (breaks.length > 0 && selectedDate) {
   504→    for (const absence of breaks) {
   505→      const absenceStart = new Date(absence.start);
   506→      const absenceEnd = new Date(absence.end);
   507→
   508→      // Get UTC date parts to build date string
   509→      const year = selectedDate.getUTCFullYear();
   510→      const month = String(selectedDate.getUTCMonth() + 1).padStart(2, "0");
   511→      const day = String(selectedDate.getUTCDate()).padStart(2, "0");
   512→      const dateString = `${year}-${month}-${day}`;
   513→
   514→      // Convert slot time from salon timezone to UTC for proper comparison
   515→      // slot.time is in the salon's local time (e.g., "14:00" in America/Sao_Paulo)
   516→      // absence.start/end are in UTC
   517→      // We need to convert slot.time to UTC to compare correctly
   518→      const timezone = salonTimezone || DEFAULT_SALON_TIMEZONE;
   519→      const slotDateTimeUTC = convertLocalToUTC(
   520→        dateString,
   521→        slot.time,
   522→        timezone
   523→      );
   524→
   525→      // Check if slot falls within break period
   526→      const isInBreak =
   527→        slotDateTimeUTC >= absenceStart && slotDateTimeUTC < absenceEnd;
   528→
   529→      if (isInBreak) {
   530→        result.blocked = true;
   531→        result.reason = absence.type;
   532→        break;
   533→      }
   534→    }
   535→  }
   536→
   537→  return result;
   538→};
   539→
   540→export function dateInTimeZone(
   541→  timeZone: string,
   542→  year: number,
   543→  month: number,
   544→  day: number,
   545→  hour = 0,
   546→  minute = 0
   547→) {
   548→  // Monta uma data "local" no formato ISO
   549→  const localStr = `${year}-${String(month).padStart(2, "0")}-${String(
   550→    day
   551→  ).padStart(2, "0")}T${String(hour).padStart(2, "0")}:${String(
   552→    minute
   553→  ).padStart(2, "0")}:00`;
   554→
   555→  // Cria a data como se fosse em UTC
   556→  const localDate = new Date(localStr);
   557→
   558→  // Usa Intl para descobrir o deslocamento do fuso
   559→  const formatter = new Intl.DateTimeFormat("en-US", {
   560→    timeZone,
   561→    hour12: false,
   562→    year: "numeric",
   563→    month: "2-digit",
   564→    day: "2-digit",
   565→    hour: "2-digit",
   566→    minute: "2-digit",
   567→    second: "2-digit",
   568→  });
   569→
   570→  // Formata e reinterpreta como UTC
   571→  const parts = formatter.formatToParts(localDate);
   572→  const map = Object.fromEntries(parts.map((p) => [p.type, p.value]));
   573→
   574→  const zonedISO = `${map.year}-${map.month}-${map.day}T${map.hour}:${map.minute}:${map.second}`;
   575→  return new Date(zonedISO);
   576→}
   577→
   578→export function parseDateInTimeZone(timeZone: string, date: Date | string) {
   579→  const finalDate = typeof date === "string" ? new Date(date) : date;
   580→  const year = finalDate.getFullYear();
   581→  const month = finalDate.getMonth() + 1;
   582→  const day = finalDate.getDate();
   583→  const hour = finalDate.getHours();
   584→  const minute = finalDate.getMinutes();
   585→
   586→  return dateInTimeZone(timeZone, year, month, day, hour, minute);
   587→}
