   628→  const slotDurationMinutes =
   629→    timeSlots.length > 1
   630→      ? timeSlots[1].hour * 60 +
   631→      timeSlots[1].minute -
   632→      (timeSlots[0].hour * 60 + timeSlots[0].minute)
