   710→   *
   711→   * As datas do backend vêm em UTC e são convertidas para o timezone do salão
   712→   * O startTimeStr já está convertido para o timezone do salão
   713→   *
   714→   * @param startTimeStr - Horário de início no formato "HH:mm" já convertido para timezone do salão
   715→   * @returns true se já passou (deve bloquear), false se ainda não passou (deve habilitar)
   716→   */
   717→  const isAbsenceBlockPassed = (startTimeStr: string): boolean => {
   718→    if (!selectedDate || !salonTimezone) {
   719→      return false;
   720→    }
   721→
   722→    // Extrair componentes da data em UTC (evita conversão para timezone local do browser)
   723→    const year = selectedDate.getUTCFullYear();
