   727→    // Criar uma data no timezone do salão usando os componentes UTC
   728→    const selectedDateInSalonTz = dateInTimeZone(
   729→      salonTimezone,
   730→      year,
   731→      month,
   732→      day,
   733→      0,
   734→      0
   735→    );
   736→
   737→    // Obter data e hora atual no timezone do salão
   738→    const nowInSalonTz = formatInTimeZone(
   739→      currentTime,
   740→      salonTimezone,
   741→      "yyyy-MM-dd HH:mm"
   742→    );
   743→    const [currentDateStr, currentTimeStr] = nowInSalonTz.split(" ");
   744→
   745→    // Obter data selecionada formatada no timezone do salão
   746→    const selectedDateStr = formatInTimeZone(
   747→      selectedDateInSalonTz,
   748→      salonTimezone,
   749→      "yyyy-MM-dd"
   750→    );
   751→
   752→    // Se a data selecionada é anterior a hoje, o bloco já passou
   753→    if (selectedDateStr < currentDateStr) {
   754→      return true;
   755→    }
   756→
   757→    // Se a data selecionada é posterior a hoje, o bloco não passou
   758→    if (selectedDateStr > currentDateStr) {
   759→      return false;
   760→    }
   761→
   762→    const [currentHour, currentMinute] = currentTimeStr.split(":").map(Number);
   763→    const currentMinutes = currentHour * 60 + currentMinute;
   764→
   765→    const startStr = formatInTimeZone(startTimeStr, salonTimezone, "HH:mm");
   766→    const [startHour, startMinute] = startStr.split(":").map(Number);
   767→    const startMinutes = startHour * 60 + startMinute;
   768→
   769→    // O bloco já passou se o horário de início é menor ou igual ao horário atual
