   771→    // Ex: São 13:12 (792 min), ausência começa às 13:00 (780 min) -> bloqueado (780 <= 792 = true)
   772→    // Ex: São 13:12 (792 min), ausência começa às 13:12 (792 min) -> bloqueado (792 <= 792 = true)
   773→    // Ex: São 13:12 (792 min), ausência começa às 13:15 (795 min) -> habilitado (795 <= 792 = false)
   774→    // Ex: São 13:12 (792 min), ausência começa às 15:00 (900 min) -> habilitado (900 <= 792 = false)
   775→    return startMinutes <= currentMinutes;
   776→  };
   777→
   778→  // Calculate absence block positions
   779→  const absenceBlocks = useMemo(() => {
