   781→
   782→    const firstSlot = timeSlots[0];
   783→    const firstSlotMinutes = firstSlot.hour * 60 + firstSlot.minute;
   784→
   785→    const slotMinutes =
   786→      timeSlots.length > 1
   787→        ? timeSlots[1].hour * 60 + timeSlots[1].minute - firstSlotMinutes
   788→        : 15;
   789→
   790→    // Calculate total visible height of the agenda
   791→    const totalVisibleSlots = timeSlots.length;
