   804→        const endMinute = endTime.minutes;
   805→
   806→        const startMinutesTotal = startHour * 60 + startMinute;
   807→        const endMinutesTotal = endHour * 60 + endMinute;
   808→
   809→        // Calculate position from first slot
   810→        const startMinutesFromFirst = startMinutesTotal - firstSlotMinutes;
   811→        const durationMinutes = endMinutesTotal - startMinutesTotal;
   812→
   813→        // Calculate top and height ensuring pixel-perfect alignment
   814→        // Round to ensure alignment with slot boundaries
   815→        let top = Math.round(
   816→          (startMinutesFromFirst / slotMinutes) * slotHeight
   817→        );
   818→        let height = Math.round((durationMinutes / slotMinutes) * slotHeight);
   819→
   820→        // Clamp to visible area
   821→        if (top < 0) {
   822→          height += top;
   823→          top = 0;
   824→        }
   825→
   826→        if (top + height > maxVisibleHeight) {
